#!/usr/bin/env python3
"""
Schurli All-in-One Server
=========================
Läuft auf dem iPad in a-Shell.

Was dieses Script macht:
  1. Liefert die Schurli-App über HTTP aus
     → iPhone öffnet http://[iPad-IP]:8080 in Safari
  2. Empfängt Druckaufträge von der App
     → Sendet sie als ESC/POS an den Epson TM-m30

Starten:  python3 schurli_server.py
Stoppen:  Ctrl+C
"""

import http.server
import json
import socket
import sys
import base64
from datetime import datetime

# ── KONFIGURATION ──────────────────────────────────────────────
DRUCKER_IP   = "192.168.1.100"  # ← Epson TM-m30 IP hier eintragen
DRUCKER_PORT = 9100              # Standard ESC/POS (nicht ändern)
SERVER_PORT  = 8080              # Port für App + Druck
# ───────────────────────────────────────────────────────────────

SCHURLI_HTML_B64 = """"""

# Dekodiere die eingebettete App
SCHURLI_HTML = base64.b64decode(SCHURLI_HTML_B64).decode('utf-8')

# ── ESC/POS BEFEHLE ────────────────────────────────────────────
ESC = b'\x1b'
GS  = b'\x1d'
CMD_INIT     = ESC + b'@'
CMD_CUT      = GS  + b'V\x41\x00'
CMD_BOLD_ON  = ESC + b'E\x01'
CMD_BOLD_OFF = ESC + b'E\x00'
CMD_CENTER   = ESC + b'a\x01'
CMD_LEFT     = ESC + b'a\x00'
CMD_FEED     = ESC + b'd'

def feed(n=3):
    return CMD_FEED + bytes([n])

def encode_text(text):
    try:
        return text.encode('cp1252')
    except Exception:
        return text.encode('latin-1', errors='replace')

def build_esc_pos(text):
    parts = [CMD_INIT]
    for line in text.split('\n'):
        s = line.strip()
        if set(s) <= {'═','─','=','-'} and len(s) > 4:
            parts += [CMD_CENTER, encode_text(line + '\n'), CMD_LEFT]
        elif s and '×' not in s and '€' not in s and 'GESAMT' not in s and len(s) < 26 and not any(c.isdigit() for c in s):
            parts += [CMD_CENTER, CMD_BOLD_ON, encode_text(line + '\n'), CMD_BOLD_OFF, CMD_LEFT]
        elif 'GESAMT' in s:
            parts += [CMD_BOLD_ON, encode_text(line + '\n'), CMD_BOLD_OFF]
        else:
            parts.append(encode_text(line + '\n'))
    parts += [feed(4), CMD_CUT]
    return b''.join(parts)

def send_to_printer(data):
    try:
        with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
            s.settimeout(5)
            s.connect((DRUCKER_IP, DRUCKER_PORT))
            s.sendall(data)
        return True, "OK"
    except socket.timeout:
        return False, f"Timeout – {DRUCKER_IP} nicht erreichbar"
    except ConnectionRefusedError:
        return False, f"Verbindung abgelehnt auf Port {DRUCKER_PORT}"
    except OSError as e:
        return False, f"Netzwerkfehler: {e}"

def get_local_ip():
    try:
        with socket.socket(socket.AF_INET, socket.SOCK_DGRAM) as s:
            s.connect(('8.8.8.8', 80))
            return s.getsockname()[0]
    except Exception:
        return '(unbekannt)'

def ts():
    return datetime.now().strftime('%H:%M:%S')

# ── HTTP HANDLER ───────────────────────────────────────────────
class SchurliHandler(http.server.BaseHTTPRequestHandler):

    def log_message(self, fmt, *args):
        print(f"[{ts()}] {fmt % args}")

    def cors(self):
        self.send_header('Access-Control-Allow-Origin', '*')
        self.send_header('Access-Control-Allow-Methods', 'GET, POST, OPTIONS')
        self.send_header('Access-Control-Allow-Headers', 'Content-Type')

    def do_OPTIONS(self):
        self.send_response(200)
        self.cors()
        self.end_headers()

    def do_GET(self):
        if self.path in ('/', '/index.html'):
            # App ausliefern
            body = SCHURLI_HTML.encode('utf-8')
            self.send_response(200)
            self.send_header('Content-Type', 'text/html; charset=utf-8')
            self.send_header('Content-Length', str(len(body)))
            self.cors()
            self.end_headers()
            self.wfile.write(body)
            print(f"[{ts()}] App ausgeliefert an {self.client_address[0]}")

        elif self.path == '/status':
            ok, msg = send_to_printer(b'')  # Ping-Versuch
            body = json.dumps({
                'server': 'Schurli Print-Bridge',
                'drucker': DRUCKER_IP,
                'drucker_status': 'erreichbar' if ok else msg
            }, ensure_ascii=False).encode('utf-8')
            self.send_response(200)
            self.send_header('Content-Type', 'application/json')
            self.cors()
            self.end_headers()
            self.wfile.write(body)

        else:
            self.send_response(404)
            self.end_headers()

    def do_POST(self):
        if self.path != '/print':
            self.send_response(404)
            self.end_headers()
            return

        try:
            length = int(self.headers.get('Content-Length', 0))
            payload = json.loads(self.rfile.read(length).decode('utf-8'))
        except Exception as e:
            self._json(400, {'ok': False, 'error': str(e)})
            return

        text = payload.get('text', '').strip()
        typ  = payload.get('type', 'bon').upper()

        if not text:
            self._json(400, {'ok': False, 'error': 'Kein Text'})
            return

        print(f"\n[{ts()}] ── {typ} ──────────────────────")
        print(text)
        print("─" * 34)

        ok, msg = send_to_printer(build_esc_pos(text))
        if ok:
            print(f"[{ts()}] ✓ Gedruckt\n")
            self._json(200, {'ok': True})
        else:
            print(f"[{ts()}] ✗ {msg}\n")
            self._json(500, {'ok': False, 'error': msg})

    def _json(self, code, data):
        body = json.dumps(data, ensure_ascii=False).encode('utf-8')
        self.send_response(code)
        self.send_header('Content-Type', 'application/json')
        self.send_header('Content-Length', str(len(body)))
        self.cors()
        self.end_headers()
        self.wfile.write(body)

# ── MAIN ───────────────────────────────────────────────────────
def main():
    ip = get_local_ip()
    print()
    print("╔══════════════════════════════════════╗")
    print("║      Schurli All-in-One Server       ║")
    print("╠══════════════════════════════════════╣")
    print(f"║  iPad-IP:  {ip:<26}║")
    print(f"║  Drucker:  {DRUCKER_IP:<26}║")
    print("╠══════════════════════════════════════╣")
    print("║  Am iPhone in Safari öffnen:         ║")
    print(f"║  http://{ip}:{SERVER_PORT:<20}║")
    print("╠══════════════════════════════════════╣")
    print("║  In Schurli > Einstellungen:         ║")
    print(f"║  Print-Bridge IP: {ip:<19}║")
    print("╠══════════════════════════════════════╣")
    print("║  Stoppen: Ctrl+C                     ║")
    print("╚══════════════════════════════════════╝")
    print()

    server = http.server.ThreadingHTTPServer(('0.0.0.0', SERVER_PORT), SchurliHandler)
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print("\nSchurli gestoppt. Tschüss! 🌿")
        server.server_close()

if __name__ == '__main__':
    main()
